#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix_estimate_revision_history.py

【対応内容】ochi-ss_システム分析レポート.md 優先対応3:
  「見積の版管理（リビジョン履歴）」

これまで見積編集(PUT /api/v1/estimates/[id])は上書き保存のみで、
変更前の内容を一切残していなかった。本スクリプトは以下を実装する:

  1. prisma/schema.prisma
     EstimateRevision モデルを新規追加(estimate_revisionsテーブル)。
     estimateHeaderId, versionNo(上書きされる直前のversion値),
     headerSnapshot(Json), detailsSnapshot(Json), changedBy, changeReason,
     createdAt を保持。削除しない監査証跡。
     EstimateHeaderに revisions リレーションを追加。

  2. src/app/api/v1/estimates/[id]/route.ts (PUT)
     版更新(version increment)の直前に、更新前のヘッダー・明細一式を
     EstimateRevisionとしてスナップショット保存するよう変更。
     (優先対応2で導入したversionチェックと同じトランザクション内で実施)

  3. src/app/api/v1/estimates/[id]/revisions/route.ts (新規, GET)
     見積のリビジョン履歴一覧を返すAPI。テナント所有チェックあり。

  4. src/lib/audit-log.ts
     AuditResource型に "estimate_revisions" を追加。

適用後、npx prisma db push(estimate_revisionsテーブルをDBに反映) →
npx prisma generate → npx tsc --noEmit --skipLibCheck を実行し、
コンパイルエラー0件の場合のみ GitHubへ自動pushする。
"""

import base64
import subprocess
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent

FILES_B64 = {
    "prisma/schema.prisma": """""",
    "src/app/api/v1/estimates/[id]/route.ts": """""",
    "src/app/api/v1/estimates/[id]/revisions/route.ts": """""",
    "src/lib/audit-log.ts": """""",
}


def run(cmd, **kwargs):
    print(f"[RUN] {' '.join(cmd)}")
    return subprocess.run(cmd, cwd=REPO_ROOT, text=True, **kwargs)


def main():
    for rel_path, b64_content in FILES_B64.items():
        target = REPO_ROOT / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content).decode("utf-8")
        target.write_text(content, encoding="utf-8")
        print(f"[OK] 書き込み完了: {rel_path}")

    print("[INFO] npx prisma db push を実行します（estimate_revisionsテーブルをDBに追加）...")
    r = run(["npx", "prisma", "db", "push"])
    if r.returncode != 0:
        print("[NG] npx prisma db push に失敗しました。中断します。")
        sys.exit(1)

    r = run(["npx", "prisma", "generate"])
    if r.returncode != 0:
        print("[NG] npx prisma generate に失敗しました。中断します。")
        sys.exit(1)

    print("[INFO] npx tsc --noEmit --skipLibCheck を実行します...")
    r = run(["npx", "tsc", "--noEmit", "--skipLibCheck"], capture_output=True)
    if r.returncode != 0:
        print("[NG] コンパイルエラーが検出されました。GitHubへのPushは行いません。")
        print(r.stdout)
        print(r.stderr)
        sys.exit(1)
    print("[OK] コンパイルエラー0件を確認しました。")

    run(["git", "add",
         "prisma/schema.prisma",
         "src/app/api/v1/estimates/[id]/route.ts",
         "src/app/api/v1/estimates/[id]/revisions/route.ts",
         "src/lib/audit-log.ts"])
    commit_msg = (
        "feat: 見積の版管理(リビジョン履歴)を実装 "
        "(EstimateRevisionモデルを追加し、編集保存の度に更新前スナップショットを保存。"
        "GET /api/v1/estimates/[id]/revisions で履歴一覧取得可能に)"
    )
    r = run(["git", "commit", "-m", commit_msg])
    if r.returncode != 0:
        print("[NG] git commit に失敗しました（差分なし、または他のエラー）。")
        sys.exit(1)

    r = run(["git", "push"])
    if r.returncode != 0:
        print("[NG] GitHubへのpushに失敗しました。手動で `git push` を実行してください。")
        sys.exit(1)
    print("[OK] GitHubへのpushが完了しました。")

    try:
        run(["pkill", "-f", "next dev"])
    except Exception:
        pass
    try:
        with open(REPO_ROOT / "dev-server.log", "ab") as logf:
            subprocess.Popen(
                ["nohup", "npm", "run", "dev"],
                cwd=REPO_ROOT, stdout=logf, stderr=logf,
                stdin=subprocess.DEVNULL, start_new_session=True,
            )
        print("[OK] 開発サーバーを再起動しました（ログ: dev-server.log）。")
    except Exception as e:
        print(f"[WARN] 開発サーバーの自動再起動に失敗しました（手動で起動してください）: {e}")

    try:
        Path(__file__).unlink()
        print("[OK] スクリプト自身を削除しました。")
    except Exception as e:
        print(f"[WARN] スクリプト自身の削除に失敗しました: {e}")


if __name__ == "__main__":
    main()
